class Solution:
    def reverseParentheses(self, s: str) -> str:
        stack = []
        for c in s:
            if c == '(':
                stack.append('')
            elif c == ')':
                temp = stack.pop()[::-1]
                if stack:
                    stack[-1] += temp
                else:
                    stack.append(temp)
            else:
                if stack:
                    stack[-1] += c
                else:
                    stack.append(c)
        return ''.join(stack)
